class Solution:
    def minAddToMakeValid(self, s: str) -> int:
        res, stack = 0, 0
        for c in s:
            if c == '(':
                stack += 1
            else:
                if stack:
                    stack -= 1
                else:
                    res += 1
        return res + stack
